#include "HybridFDN16.h"
void HybridFDN16::prepare(const juce::dsp::ProcessSpec& s){sampleRate=s.sampleRate;for(int i=0;i<16;++i){delays[(size_t)i].prepare(sampleRate,.5);phases[(size_t)i]=(float)i/16.0f;rates[(size_t)i]=.07f+.011f*(float)i;}reset();}
void HybridFDN16::reset(){for(auto& d:delays)d.reset();feedback.fill(0);dampingState.fill(0);}
void HybridFDN16::setParameters(float d,float sz,float damp,float dif,float den,float mod,bool fr){decay=juce::jlimit(.2f,60.0f,d);size=juce::jlimit(.25f,2.0f,sz*.01f);damping=juce::jlimit(800.0f,20000.0f,damp);diffusion=juce::jlimit(0.0f,1.0f,dif*.01f);density=juce::jlimit(0.0f,1.0f,den*.01f);modulation=juce::jlimit(0.0f,1.0f,mod*.01f);freeze=fr;}
void HybridFDN16::processStereo(float l,float r,float& outL,float& outR) noexcept { auto m=feedback; Matrix16::hadamard(m); outL=outR=0; float dc=std::exp(-juce::MathConstants<float>::twoPi*damping/(float)sampleRate); for(int i=0;i<16;++i){auto k=(size_t)i; phases[k]+=rates[k]/(float)sampleRate; if(phases[k]>=1)phases[k]-=1; float ms=baseMs[k]*size+std::sin(juce::MathConstants<float>::twoPi*phases[k])*modulation*.8f; delays[k].setDelaySamples(ms*.001f*(float)sampleRate); float g=freeze?.9999f:std::pow(.001f,baseMs[k]*.001f/decay); float inj=freeze?0.0f:((i&1)?r:l)*.12f; float y=delays[k].process(inj+m[k]*g*juce::jmap(density,.72f,1.0f)); dampingState[k]=y*(1-dc)+dampingState[k]*dc; feedback[k]=juce::jmap(diffusion,y,dampingState[k]); float s=feedback[k]*.12f; outL+=((i%4)<2?1.0f:-1.0f)*s; outR+=(((i+1)%4)<2?1.0f:-1.0f)*s;} }
